import pandas as pd

from pytexera import *
class Operator(UDFGeneralOperator):
    def process_table_0(self, df1: pd.DataFrame, df2: pd.DataFrame):
        self.left = pd.merge(df1, df2, on='id', how='inner')
        yield None
    def process_table_1(self):
        self.left['score'] = self.left['a'] + self.left['b']
        yield None
    def process_table_2(self, df3: pd.DataFrame):
        self.final = pd.merge(self.left, df3, on='id', how='inner')
        yield self.final[['id', 'score', 'label']]
